// src/components/Common/cvsection.js
import React, { useState } from "react";

export default function CVSection({ workerInfo, isEditable = false, onSave }) {
  const [showModal, setShowModal] = useState(false);
  
  // بيانات التعديل - مستقلة تماماً
  const [formData, setFormData] = useState({
    name: "",
    role: "",
    experience: "",
    skills: [],
    bio: "",
    email: "",
    phone: "",
    location: "",
    languages: []
  });
  
  const [newSkill, setNewSkill] = useState("");

  // فتح المودال ونسخ البيانات
  const openModal = () => {
    setFormData({
      name: workerInfo.name || "",
      role: workerInfo.role || "",
      experience: workerInfo.experience || "",
      skills: [...(workerInfo.skills || [])],
      bio: workerInfo.bio || "",
      email: workerInfo.email || "",
      phone: workerInfo.phone || "",
      location: workerInfo.location || "",
      languages: [...(workerInfo.languages || [])]
    });
    setShowModal(true);
  };

  // إغلاق المودال
  const closeModal = () => {
    setShowModal(false);
    setNewSkill("");
  };

  // تغيير الحقول
  const handleChange = (field, value) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  // إضافة مهارة
  const addSkill = () => {
    if (newSkill.trim() && !formData.skills.includes(newSkill.trim())) {
      setFormData(prev => ({
        ...prev,
        skills: [...prev.skills, newSkill.trim()]
      }));
      setNewSkill("");
    }
  };

  // حذف مهارة
  const removeSkill = (skill) => {
    setFormData(prev => ({
      ...prev,
      skills: prev.skills.filter(s => s !== skill)
    }));
  };

  // حفظ التغييرات
  const saveChanges = () => {
    if (onSave) {
      onSave(formData);
    }
    closeModal();
  };

  // الأنماط
  const styles = `
    .cv-card {
      text-align: center;
    }
    .cv-icon {
      font-size: 4rem;
      margin-bottom: 1rem;
    }
    .cv-name {
      color: white;
      font-size: 1.5rem;
      font-weight: bold;
      margin-bottom: 0.5rem;
    }
    .cv-role {
      color: #22c55e;
      margin-bottom: 1rem;
    }
    .section-title {
      color: white;
      font-size: 1.2rem;
      font-weight: bold;
      margin-top: 1.5rem;
      margin-bottom: 0.75rem;
    }
    .cv-text {
      color: rgba(255,255,255,0.85);
      line-height: 1.5;
    }
    .cv-contact {
      color: rgba(255,255,255,0.8);
      margin: 0.25rem 0;
    }
    .skill-badge {
      display: inline-block;
      padding: 5px 12px;
      background: rgba(34,197,94,0.2);
      border-radius: 20px;
      font-size: 12px;
      margin: 3px;
      color: #4ade80;
      border: 1px solid rgba(34,197,94,0.4);
    }
    .edit-btn {
      background: linear-gradient(135deg, #22c55e, #15803d);
      border: none;
      padding: 10px 20px;
      border-radius: 25px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      width: 100%;
      margin-top: 20px;
    }
    .edit-btn:hover {
      transform: scale(1.02);
    }
    /* Modal */
    .modal-overlay-new {
      position: fixed;
      top: 0;
      left: 0;
      right: 0;
      bottom: 0;
      background: rgba(0,0,0,0.95);
      backdrop-filter: blur(12px);
      z-index: 20000;
      display: flex;
      align-items: center;
      justify-content: center;
    }
    .modal-new {
      background: linear-gradient(135deg, #1a1a3a, #0d0d2b);
      border-radius: 30px;
      padding: 30px;
      max-width: 550px;
      width: 90%;
      max-height: 85vh;
      overflow-y: auto;
      border: 2px solid #22c55e;
    }
    .modal-new::-webkit-scrollbar {
      width: 6px;
    }
    .modal-new::-webkit-scrollbar-track {
      background: rgba(255,255,255,0.1);
      border-radius: 10px;
    }
    .modal-new::-webkit-scrollbar-thumb {
      background: #22c55e;
      border-radius: 10px;
    }
    .close-modal {
      float: right;
      background: none;
      border: none;
      color: white;
      font-size: 24px;
      cursor: pointer;
    }
    .close-modal:hover {
      color: #ef4444;
    }
    .modal-title {
      color: white;
      font-size: 1.5rem;
      font-weight: bold;
      text-align: center;
      margin-bottom: 20px;
    }
    .input-group {
      margin-bottom: 15px;
    }
    .input-group label {
      display: block;
      color: white;
      font-size: 0.85rem;
      margin-bottom: 5px;
    }
    .input-group input,
    .input-group textarea {
      width: 100%;
      padding: 12px;
      background: rgba(255,255,255,0.1);
      border: 1px solid rgba(34,197,94,0.3);
      border-radius: 15px;
      color: white;
      font-size: 0.9rem;
    }
    .input-group input:focus,
    .input-group textarea:focus {
      outline: none;
      border-color: #22c55e;
    }
    .skills-container {
      display: flex;
      flex-wrap: wrap;
      gap: 8px;
      margin-bottom: 10px;
    }
    .skill-item {
      background: rgba(34,197,94,0.15);
      border-radius: 20px;
      padding: 5px 12px;
      color: #4ade80;
      font-size: 12px;
      display: inline-flex;
      align-items: center;
      gap: 6px;
    }
    .remove-skill {
      background: none;
      border: none;
      color: #ef4444;
      cursor: pointer;
      font-size: 14px;
    }
    .add-skill-row {
      display: flex;
      gap: 10px;
    }
    .add-skill-input {
      flex: 1;
      padding: 10px;
      background: rgba(255,255,255,0.1);
      border: 1px solid rgba(34,197,94,0.3);
      border-radius: 15px;
      color: white;
    }
    .add-skill-btn {
      background: #22c55e;
      border: none;
      padding: 10px 15px;
      border-radius: 25px;
      color: white;
      cursor: pointer;
    }
    .save-btn {
      background: linear-gradient(135deg, #22c55e, #15803d);
      border: none;
      padding: 12px;
      border-radius: 25px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      width: 100%;
      margin-top: 20px;
    }
    .cancel-btn {
      background: linear-gradient(135deg, #6b7280, #4b5563);
      border: none;
      padding: 12px;
      border-radius: 25px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      width: 100%;
      margin-top: 10px;
    }
    @media (max-width: 480px) {
      .modal-new { padding: 20px; }
      .add-skill-row { flex-direction: column; }
      .add-skill-btn { width: 100%; }
    }
  `;

  // عرض CV (وضع القراءة)
  const CVView = () => (
    <div className="cv-card">
      <div className="cv-icon">👩‍💻</div>
      <h2 className="cv-name">{workerInfo.name}</h2>
      <p className="cv-role">{workerInfo.role}</p>
      <div style={{ textAlign: "left" }}>
        <h3 className="section-title">📋 Profil</h3>
        <p className="cv-text">{workerInfo.bio}</p>
        
        <h3 className="section-title">💪 Compétences</h3>
        <div>
          {workerInfo.skills?.map((skill, i) => (
            <span key={i} className="skill-badge">{skill}</span>
          ))}
        </div>
        
        <h3 className="section-title">📞 Contact</h3>
        <p className="cv-contact">📧 {workerInfo.email}</p>
        <p className="cv-contact">📱 {workerInfo.phone}</p>
        <p className="cv-contact">📍 {workerInfo.location}</p>
        
        <h3 className="section-title">🎓 Expérience</h3>
        <p className="cv-text">{workerInfo.experience}</p>
        
        {workerInfo.languages && workerInfo.languages.length > 0 && (
          <>
            <h3 className="section-title">🌐 Langues</h3>
            <div>
              {workerInfo.languages.map((lang, i) => (
                <span key={i} className="skill-badge">{lang}</span>
              ))}
            </div>
          </>
        )}
      </div>
      {isEditable && (
        <button className="edit-btn" onClick={openModal}>✏️ Modifier CV</button>
      )}
    </div>
  );

  // مودال التعديل
  const EditModal = () => (
    <div className="modal-overlay-new" onClick={closeModal}>
      <div className="modal-new" onClick={(e) => e.stopPropagation()}>
        <button className="close-modal" onClick={closeModal}>✕</button>
        <h2 className="modal-title">✏️ Modifier le CV</h2>
        
        <div className="input-group">
          <label>👤 Nom complet</label>
          <input type="text" value={formData.name} onChange={(e) => handleChange("name", e.target.value)} />
        </div>
        
        <div className="input-group">
          <label>💼 Titre du poste</label>
          <input type="text" value={formData.role} onChange={(e) => handleChange("role", e.target.value)} />
        </div>
        
        <div className="input-group">
          <label>📧 Email</label>
          <input type="email" value={formData.email} onChange={(e) => handleChange("email", e.target.value)} />
        </div>
        
        <div className="input-group">
          <label>📱 Téléphone</label>
          <input type="tel" value={formData.phone} onChange={(e) => handleChange("phone", e.target.value)} />
        </div>
        
        <div className="input-group">
          <label>📍 Localisation</label>
          <input type="text" value={formData.location} onChange={(e) => handleChange("location", e.target.value)} />
        </div>
        
        <div className="input-group">
          <label>📝 Bio</label>
          <textarea rows="3" value={formData.bio} onChange={(e) => handleChange("bio", e.target.value)} />
        </div>
        
        <div className="input-group">
          <label>🎓 Expérience</label>
          <input type="text" value={formData.experience} onChange={(e) => handleChange("experience", e.target.value)} />
        </div>
        
        <div className="input-group">
          <label>🌐 Langues (séparées par des virgules)</label>
          <input type="text" value={formData.languages.join(", ")} onChange={(e) => handleChange("languages", e.target.value.split(",").map(l => l.trim()))} />
        </div>
        
        <div className="input-group">
          <label>💪 Compétences</label>
          <div className="skills-container">
            {formData.skills.map((skill, i) => (
              <span key={i} className="skill-item">
                {skill}
                <button className="remove-skill" onClick={() => removeSkill(skill)}>✕</button>
              </span>
            ))}
          </div>
          <div className="add-skill-row">
            <input 
              type="text" 
              className="add-skill-input" 
              placeholder="Ajouter une compétence..." 
              value={newSkill} 
              onChange={(e) => setNewSkill(e.target.value)} 
              onKeyPress={(e) => e.key === 'Enter' && addSkill()} 
            />
            <button className="add-skill-btn" onClick={addSkill}>+ Ajouter</button>
          </div>
        </div>
        
        <button className="save-btn" onClick={saveChanges}>💾 Enregistrer</button>
        <button className="cancel-btn" onClick={closeModal}>❌ Annuler</button>
      </div>
    </div>
  );

  return (
    <>
      <style>{styles}</style>
      <CVView />
      {showModal && <EditModal />}
    </>
  );
}
